                    jm_call_void_2(mt, "js_throw_const_assign",
                        MIR_T_I64, MIR_new_int_op(mt->ctx, (int64_t)(uintptr_t)id->name->chars),
                        MIR_T_I64, MIR_new_int_op(mt->ctx, (int64_t)id->name->len));
