                    jm_call_3(mt, "js_property_set", MIR_T_I64,
                        MIR_T_I64, MIR_new_reg_op(mt->ctx, obj),
                        MIR_T_I64, MIR_new_reg_op(mt->ctx, key),
                        MIR_T_I64, MIR_new_reg_op(mt->ctx, result));
