            if (obj->name && obj->name->len == 4 && strncmp(obj->name->chars, "Date", 4) == 0 &&
                prop->name && prop->name->len == 3 && strncmp(prop->name->chars, "now", 3) == 0) {
                return jm_call_0(mt, "js_date_now", MIR_T_I64);
            }
